-- =====================================================
-- Migration: 20260617000000_pr6c2_retag_apply.sql
-- =====================================================
-- Description:
--   PR C2 — Stage 2 corpus re-tag APPLY (data write to all 12 re-tagged
--   metadata fields across the live corpus). This migration writes the
--   reviewed, corrected Stage-2 re-tag output to PRODUCTION: for every
--   changing lesson it dual-writes BOTH the lessons text[] columns AND the
--   matching camelCase metadata JSONB keys (the census-confirmed dual
--   representation). academic_concepts is JSONB-only (no text[] column).
--
--   Cultural heritage is stored SPECIFIC-ONLY (the heritage pivot, Option B):
--   the run's specific tags minus the targeted drops, stored as-is with NO
--   parent-chain expansion. The recursive filter that makes specific-only
--   storage safe shipped in PR C1 (20260616000000_heritage_recursive_expansion).
--
--   Compared/staged/changing lessons: 753 (the C2.1-regenerated staged set).
--
-- =====================================================
-- SECTIONS (LOAD-BEARING ORDER)
-- =====================================================
--   (1)  pr6_retag_rollback DDL — snapshot table (text[] cols + metadata jsonb
--        + content_text). RLS enabled, NO policies (service-role-only).
--   (2)  Snapshot INSERT...SELECT...ON CONFLICT DO NOTHING — captures the
--        ORIGINAL values of every row about to change. WHERE set = the 753
--        changing ids (which already include Who's-Who) UNION the retired row
--        15T4wU94... (so both special-case repairs in (4)/(5) are reversible).
--   (3)  Per-lesson dual-write UPDATEs (absolute values; heritage-corrected +
--        grade-guarded). 753 blocks, copied verbatim from the C2.1-regenerated
--        prepare-apply draft. 25 empty-run-grade rows correctly OMIT both the
--        grade_levels column write and the metadata.gradeLevels jsonb_set
--        (existing grades are preserved, never blanked); 728 rows write grades.
--   (4)  Who's-Who content_text repair (length-guarded -> idempotent).
--   (5)  Retired fold-fix: Food Justice -> Social Justice on the lone retired
--        non-canonical row (makes the whole table canonical for the CHECKs).
--   (6)  Six small-field CHECK constraints — added AFTER the data is canonical
--        (ordering load-bearing). heritage + academic_concepts get NO CHECK.
--   (7)  U-1 integrity assertion (DERIVED forbidden-label set, hard-fail).
--   (8)  ANALYZE public.lessons.
--
-- =====================================================
-- IDEMPOTENCY
-- =====================================================
--   * (1) CREATE TABLE IF NOT EXISTS.
--   * (2) ON CONFLICT (lesson_id) DO NOTHING — preserves the FIRST pre-apply
--         snapshot on any re-run (PR-5a precedent); a re-run does NOT overwrite
--         the original snapshot with already-applied values.
--   * (3) UPDATEs set ABSOLUTE values -> re-running is a no-op.
--   * (4) length(content_text) < 1000 guard -> no-op once repaired.
--   * (5) array_replace on an already-folded row is a no-op; the metadata
--         rebuild is value-guarded (only touches rows still carrying the value).
--   * (6) DO $$ ... pg_constraint existence check ... ADD CONSTRAINT $$ blocks.
--   * (7)/(8) read-only assertion / ANALYZE — always safe to re-run.
--
-- Precedents: 20260611000000_pr5a_heritage_canonicalization (rollback table +
--   ON CONFLICT snapshot), 20260515000000_metadata_value_validation (idempotent
--   pg_constraint-guarded CHECK pattern + value-guarded jsonb array rebuild),
--   20260616000000_heritage_recursive_expansion (expand_cultural_heritage,
--   reused in (7) to DERIVE the forbidden label set).
-- =====================================================


-- =====================================================
-- (1) Rollback snapshot table — original values of every changing row.
--     Extends the B5/draft snapshot with content_text (for the Who's-Who
--     content_text repair rollback). Service-role-only: RLS enabled, NO policies.
-- =====================================================
CREATE TABLE IF NOT EXISTS public.pr6_retag_rollback (
  lesson_id text PRIMARY KEY,
  activity_type text[],
  tags text[],
  season_timing text[],
  cultural_responsiveness_features text[],
  cultural_heritage text[],
  academic_integration text[],
  social_emotional_learning text[],
  core_competencies text[],
  cooking_methods text[],
  observances_holidays text[],
  garden_skills text[],
  grade_levels text[],
  content_text text,
  metadata jsonb
);
-- Service-role-only: RLS enabled with NO policies.
ALTER TABLE public.pr6_retag_rollback ENABLE ROW LEVEL SECURITY;


