-- =====================================================
-- (5) Retired fold-fix: Food Justice -> Social Justice.
--     The lone RETIRED non-canonical row 15T4wU94... ("Children's Aid Society:
--     Food Justice Program", retired_at IS NOT NULL) still carries the
--     non-canonical 'Food Justice' value in core_competencies (column + the
--     metadata.coreCompetencies array — verified array-shape, key 'coreCompetencies').
--     Folding it to the canonical 'Social Justice' makes the WHOLE lessons table
--     canonical so the valid_core_competencies CHECK in (6) can install.
--     Mirrored on BOTH the column and the metadata key. Idempotent:
--     array_replace on an already-folded array is a no-op, and the metadata
--     rebuild only fires on rows still containing the value.
-- =====================================================
-- Column side: array_replace returns the array unchanged when the value is absent.
UPDATE public.lessons
SET core_competencies = array_replace(core_competencies, 'Food Justice', 'Social Justice')
WHERE lesson_id = '15T4wU94xT3r-dRx-WJq9XD2-ySg2HKaz'
  AND 'Food Justice' = ANY(core_competencies);

-- Metadata side: rebuild the JSON array element-by-element with CASE replacement.
UPDATE public.lessons
SET metadata = jsonb_set(
  metadata,
  '{coreCompetencies}',
  (
    SELECT jsonb_agg(
      CASE WHEN val = 'Food Justice'
        THEN to_jsonb('Social Justice'::text)
        ELSE to_jsonb(val)
      END
    )
    FROM jsonb_array_elements_text(metadata->'coreCompetencies') AS val
  )
)
WHERE lesson_id = '15T4wU94xT3r-dRx-WJq9XD2-ySg2HKaz'
  AND jsonb_typeof(metadata->'coreCompetencies') = 'array'
  AND metadata->'coreCompetencies' @> '"Food Justice"'::jsonb;


-- =====================================================
-- (6) Six small-field CHECK constraints — added AFTER the data is canonical
--     (the (3) per-lesson UPDATEs + the (5) retired fold-fix). Idempotent via
--     DO blocks (pg_constraint existence check), per the
--     20260515000000_metadata_value_validation precedent. Vocab arrays are
--     copied VERBATIM from scripts/stage2-retag/data/smaller-fields.vocab.json.
--     heritage + academic_concepts get NO CHECK (open/structured vocab).
-- =====================================================
DO $$
BEGIN
  -- SOURCE: smaller-fields.vocab.json.fields.academic_integration (6 values)
  IF NOT EXISTS (
    SELECT 1 FROM pg_constraint
    WHERE conname = 'valid_academic_integration'
      AND conrelid = 'public.lessons'::regclass
  ) THEN
    ALTER TABLE public.lessons
      ADD CONSTRAINT valid_academic_integration
      CHECK (
        academic_integration IS NULL
        OR academic_integration <@ ARRAY[
          'Math',
          'Science',
          'Literacy/ELA',
          'Social Studies',
          'Health',
          'Arts'
        ]::text[]
      );
  END IF;

  -- SOURCE: smaller-fields.vocab.json.fields.social_emotional_learning (5 values)
  IF NOT EXISTS (
    SELECT 1 FROM pg_constraint
    WHERE conname = 'valid_social_emotional_learning'
      AND conrelid = 'public.lessons'::regclass
  ) THEN
    ALTER TABLE public.lessons
      ADD CONSTRAINT valid_social_emotional_learning
      CHECK (
        social_emotional_learning IS NULL
        OR social_emotional_learning <@ ARRAY[
          'Relationship skills',
          'Self-awareness',
          'Responsible decision-making',
          'Self-management',
          'Social awareness'
        ]::text[]
      );
  END IF;

  -- SOURCE: smaller-fields.vocab.json.fields.core_competencies (6 values)
  IF NOT EXISTS (
    SELECT 1 FROM pg_constraint
    WHERE conname = 'valid_core_competencies'
      AND conrelid = 'public.lessons'::regclass
  ) THEN
    ALTER TABLE public.lessons
      ADD CONSTRAINT valid_core_competencies
      CHECK (
        core_competencies IS NULL
        OR core_competencies <@ ARRAY[
          'Environmental and Community Stewardship',
          'Social Justice',
          'Social-Emotional Intelligence',
          'Garden Skills and Related Academic Content',
          'Kitchen Skills and Related Academic Content',
          'Culturally Responsive Education'
        ]::text[]
      );
  END IF;

  -- SOURCE: smaller-fields.vocab.json.fields.cooking_methods (3 values)
  IF NOT EXISTS (
    SELECT 1 FROM pg_constraint
    WHERE conname = 'valid_cooking_methods'
      AND conrelid = 'public.lessons'::regclass
  ) THEN
    ALTER TABLE public.lessons
      ADD CONSTRAINT valid_cooking_methods
      CHECK (
        cooking_methods IS NULL
        OR cooking_methods <@ ARRAY[
          'basic-prep',
          'stovetop',
          'oven'
        ]::text[]
      );
  END IF;

  -- SOURCE: smaller-fields.vocab.json.fields.observances_holidays (16 values)
  IF NOT EXISTS (
    SELECT 1 FROM pg_constraint
    WHERE conname = 'valid_observances_holidays'
      AND conrelid = 'public.lessons'::regclass
  ) THEN
    ALTER TABLE public.lessons
      ADD CONSTRAINT valid_observances_holidays
      CHECK (
        observances_holidays IS NULL
        OR observances_holidays <@ ARRAY[
          'AAPI Heritage Month',
          'Black History Month',
          'Hispanic/Latinx Heritage Month',
          'Indigenous Peoples'' Month',
          'Women''s History Month',
          'Pride',
          'Earth Month',
          'Thanksgiving',
          'Lunar New Year',
          'New Year',
          'Ramadan',
          'Eid',
          'Juneteenth',
          'School Food Hero Day',
          'Beginning of year',
          'End of year celebrations'
        ]::text[]
      );
  END IF;

  -- SOURCE: smaller-fields.vocab.json.fields.garden_skills (24 values)
  IF NOT EXISTS (
    SELECT 1 FROM pg_constraint
    WHERE conname = 'valid_garden_skills'
      AND conrelid = 'public.lessons'::regclass
  ) THEN
    ALTER TABLE public.lessons
      ADD CONSTRAINT valid_garden_skills
      CHECK (
        garden_skills IS NULL
        OR garden_skills <@ ARRAY[
          'Planting',
          'Seed starting',
          'Transplanting',
          'Watering techniques',
          'Harvesting',
          'Composting',
          'Mulching',
          'Soil preparation and care',
          'Weeding',
          'Cover cropping',
          'Garden planning',
          'Companion planting',
          'Crop rotation',
          'Observing plant parts',
          'Identifying plants',
          'Pest identification',
          'Beneficial insect identification',
          'Pollinator observation',
          'Seed saving',
          'Tool use and maintenance',
          'Preservation techniques',
          'Garden exploration',
          'Stewardship tasks',
          'Sensory exploration'
        ]::text[]
      );
  END IF;
END $$;


-- =====================================================
-- (7) U-1 integrity assertion (hard-fail).
--     The identity anchor: no live (retired_at IS NULL) lesson may carry the
--     generic 'North American' label alongside ANY Indigenous-and-Diaspora
--     identity label (African American / Indigenous / Soul Food / Lenape /
--     Haudenosaunee / Three Sisters traditions / Cajun/Creole / Black culinary
--     history / Indigenous and Diaspora). The forbidden set is DERIVED at
--     runtime by recursively expanding the 'indigenous-and-diaspora' subtree
--     from the LIVE hierarchy via expand_cultural_heritage (shipped in
--     20260616000000) — NOT hand-listed, so it stays correct as the tree
--     evolves and cannot omit a leaf (the Codex finding this section fixes).
--     Checked on BOTH the cultural_heritage text[] column AND the
--     metadata->'culturalHeritage' JSONB mirror.
-- =====================================================
DO $$
DECLARE
  v_forbidden text[];
  v_col_violations bigint;
  v_meta_violations bigint;
BEGIN
  -- Derive the forbidden Indigenous-and-Diaspora label set from the live tree.
  v_forbidden := public.expand_cultural_heritage(ARRAY['indigenous-and-diaspora']);

  IF v_forbidden IS NULL OR array_length(v_forbidden, 1) IS NULL THEN
    RAISE EXCEPTION 'U-1 assertion could not derive the Indigenous-and-Diaspora label set from expand_cultural_heritage(); aborting apply.';
  END IF;

  -- Column side: live rows carrying 'North American' AND any derived label.
  SELECT count(*) INTO v_col_violations
  FROM public.lessons l
  WHERE l.retired_at IS NULL
    AND 'North American' = ANY(l.cultural_heritage)
    AND l.cultural_heritage && v_forbidden;

  -- Metadata mirror side: same check against metadata->'culturalHeritage'.
  SELECT count(*) INTO v_meta_violations
  FROM public.lessons l
  WHERE l.retired_at IS NULL
    AND jsonb_typeof(l.metadata->'culturalHeritage') = 'array'
    AND l.metadata->'culturalHeritage' @> '"North American"'::jsonb
    AND EXISTS (
      SELECT 1
      FROM jsonb_array_elements_text(l.metadata->'culturalHeritage') AS v(label)
      WHERE v.label = ANY(v_forbidden)
    );

  IF v_col_violations > 0 OR v_meta_violations > 0 THEN
    RAISE EXCEPTION 'U-1 integrity assertion FAILED: % live row(s) carry North American + an Indigenous-and-Diaspora identity label on the column, % on the metadata mirror. Forbidden set = %.',
      v_col_violations, v_meta_violations, array_to_string(v_forbidden, ', ');
  END IF;

  RAISE NOTICE 'U-1 assertion passed (0 column / 0 metadata violations) against derived set: %', array_to_string(v_forbidden, ', ');
END $$;


